type Variant = keyof typeof PATHS;

function stringSeed(text: string): number {
  return Array.from(text).reduce((acc, c) => acc + c.charCodeAt(0), 0);
}

function pickVariant(seed: number, variant?: Variant): { path: string } {
  const types = Object.keys(PATHS) as Variant[];
  const type = variant ?? types[seed % types.length];
  const paths = PATHS[type];
  if (!paths) {
    const fallback = PATHS[types[0]];
    return { path: fallback[seed % fallback.length] };
  }
  return { path: paths[seed % paths.length] };
}

// ── Shared SVG layer ──────────────────────────────────────────────────────────

interface PathLayerProps {
  seed: number;
  variant?: Variant;
  className?: string;
  delay?: number;
  duration?: number;
}

const PathLayer: React.FC<PathLayerProps> = ({
  seed,
  variant,
  className,
  delay = 0,
  duration = 0.5,
}) => {
  const { path } = useMemo(() => pickVariant(seed, variant), [seed, variant]);

  const rotate = useMemo(() => ((seed % 9) - 4) * 0.1, [seed]);

  return (
    <svg
      aria-hidden
      className={cn(
        'pointer-events-none absolute left-0 h-4 w-full fill-none overflow-visible -z-10',
        className,
      )}
      viewBox="0 0 200 24"
      preserveAspectRatio="none"
      strokeLinecap="round"
      strokeLinejoin="round"
      data-variant={variant}
      style={{ transform: `rotate(${rotate}deg)` }}
    >
      <motion.path
        d={path}
        vectorEffect="non-scaling-stroke"
        initial={{ pathLength: 0, opacity: 0 }}
        animate={{ pathLength: 1.75, opacity: 1 }}
        transition={{
          pathLength: { duration, ease: 'easeOut', delay },
          opacity: { duration: duration * 0.3, ease: 'easeOut', delay },
        }}
      />
    </svg>
  );
};

// ── Single word wrapper ───────────────────────────────────────────────────────

interface WordProps {
  word: string;
  wordIndex: number;
  renderLayer: (seed: number, wordIndex: number) => React.ReactNode;
}

const Word: React.FC<WordProps> = ({ word, wordIndex, renderLayer }) => {
  const seed = useMemo(() => stringSeed(word) + wordIndex, [word, wordIndex]);

  return (
    <span className="relative inline-block">
      {word}
      {renderLayer(seed, wordIndex)}
    </span>
  );
};

// ── Word splitter ─────────────────────────────────────────────────────────────

function groupChunks(words: string[], maxChunkLength: number): string[] {
  const groups: string[] = [];
  let current = '';

  for (const word of words) {
    if (current === '') {
      current = word;
    } else if (current.length + 1 + word.length <= maxChunkLength) {
      current += ' ' + word;
    } else {
      groups.push(current);
      current = word;
    }
  }

  if (current) groups.push(current);

  return groups;
}

interface WordSplitterProps {
  children: string;
  as?: keyof React.JSX.IntrinsicElements;
  className?: string;
  maxChunkLength?: number;
  variant?: Variant;
  renderLayer: (
    seed: number,
    wordIndex: number,
    variant: Variant,
  ) => React.ReactNode;
}

const WordSplitter: React.FC<WordSplitterProps> = ({
  children,
  as: Tag = 'span',
  className,
  maxChunkLength = 18,
  variant,
  renderLayer,
}) => {
  const groups = useMemo(() => {
    const words = children.trim().split(/\s+/);
    return groupChunks(words, maxChunkLength);
  }, [children, maxChunkLength]);

  const resolvedVariant = useMemo(() => {
    const types = Object.keys(PATHS) as Variant[];
    return variant ?? types[stringSeed(children) % types.length];
  }, [children, variant]);

  return (
    <Tag className={cn('inline', className)}>
      {groups.map((group, i) => (
        <React.Fragment key={i}>
          {i > 0 && ' '}
          <Word
            word={group}
            wordIndex={i}
            renderLayer={(seed, wordIndex) =>
              renderLayer(seed, wordIndex, resolvedVariant)
            }
          />
        </React.Fragment>
      ))}
    </Tag>
  );
};

function flattenChildren(children: React.ReactNode): string {
  if (typeof children === 'string') return children;
  if (typeof children === 'number') return String(children);
  if (Array.isArray(children)) return children.map(flattenChildren).join('');
  if (React.isValidElement(children)) {
    return flattenChildren(
      (children.props as { children?: React.ReactNode }).children,
    );
  }
  return '';
}

// ── Public components ─────────────────────────────────────────────────────────

interface AnnotationProps {
  children: React.ReactNode;
  as?: keyof React.JSX.IntrinsicElements;
  className?: string;
  delay?: number;
  duration?: number;
  stagger?: number;
  variant?: Variant;
  maxChunkLength?: number;
  tagClassName?: string;
}

export const Highlight: React.FC<AnnotationProps> = ({
  children,
  className,
  tagClassName,
  delay = 0.2,
  duration = 2,
  stagger = 0.2,
  ...props
}) => {
  const text = useMemo(() => flattenChildren(children), [children]);
  return (
    <WordSplitter
      className={tagClassName}
      {...props}
      renderLayer={(seed, wordIndex, resolvedVariant) => (
        <PathLayer
          seed={seed}
          variant={resolvedVariant}
          className={cn(
            'top-1/2 -translate-y-1/2 stroke-[1em] h-[0.75em] stroke-yellow-200',
            className,
          )}
          delay={delay + wordIndex * stagger}
          duration={duration}
        />
      )}
    >
      {text}
    </WordSplitter>
  );
};

export const Underline: React.FC<AnnotationProps> = ({
  children,
  className,
  delay = 1,
  duration = 1,
  stagger = 0.5,
  ...props
}) => {
  const text = useMemo(() => flattenChildren(children), [children]);
  return (
    <WordSplitter
      {...props}
      renderLayer={(seed, wordIndex, resolvedVariant) => (
        <PathLayer
          seed={seed}
          variant={resolvedVariant}
          className={cn(
            '-bottom-[0.15em] h-3 stroke-2 stroke-yellow-500',
            className,
          )}
          delay={delay + wordIndex * stagger}
          duration={duration}
        />
      )}
    >
      {text}
    </WordSplitter>
  );
};
